            priceCents={80000}
            currency="EUR"
            preConditionSummary="20K+ Instagram followers"
            status="approved"
            onPress={() => {}}
            testID="card-summer-travel"
          />
          <SkeletonCard height={160} testID="skeleton-card" />
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

