import { useEffect } from 'react';
import { Slot } from 'expo-router';
import { GestureHandlerRootView } from 'react-native-gesture-handler';
import { StatusBar } from 'expo-status-bar';
import { useFonts } from 'expo-font';
import * as SplashScreen from 'expo-splash-screen';
import { fontAssets } from '@/design/typography';
import { ToastProvider } from '@/components/primitives/Toast';

// Hold the splash screen until custom fonts register — text with an unregistered
// fontFamily silently falls back to System on iOS and the swap is visible to the user.
// Promise rejects if the splash was already dismissed (fast-refresh, dev reloads) —
// swallow so Metro doesn't see an unhandled rejection.
SplashScreen.preventAutoHideAsync().catch(() => {});

export default function RootLayout() {
  const [fontsLoaded, fontError] = useFonts(fontAssets);

  useEffect(() => {
    if (fontsLoaded || fontError) {
      SplashScreen.hideAsync();
    }
  }, [fontsLoaded, fontError]);

  if (!fontsLoaded && !fontError) {
    return null;
  }

  return (
    <GestureHandlerRootView style={{ flex: 1 }}>
      <ToastProvider>
        <Slot />
      </ToastProvider>
      <StatusBar style="auto" />
    </GestureHandlerRootView>
  );
}

import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import {
  type LayoutChangeEvent,
  Pressable,
  SafeAreaView,
  StyleSheet,
  Text,
  View,
} from 'react-native';
import Animated, {
  cancelAnimation,
  Easing,
  useAnimatedStyle,
  useSharedValue,
  withSpring,
  withTiming,
  type WithSpringConfig,
} from 'react-native-reanimated';
import { X } from 'lucide-react-native';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { SPRING_SNAPPY, withReducedMotion } from '@/design/motion';
import { useReducedMotion } from '@/design/useReducedMotion';
import { textStyles } from '@/design/typography';

// Global toast banner per docs/design.md §6 inventory (`message, variant, duration`)
// and §1.4 line 439 ("2.5s success toast"). Mount ToastProvider once near the root
// (app/_layout.tsx) and call useToast().show({...}) from anywhere.
//
// Variants drive the soft-bg + border color from the semantic palette in §1.2.
// Progress bar counts down the remaining duration so the user can gauge when it
// will auto-dismiss.

export type ToastVariant = 'success' | 'error' | 'info';

export type ToastPayload = {
  message: string;
  variant?: ToastVariant;
  duration?: number; // ms, default 2500
};

type ToastContextValue = {
  show: (t: ToastPayload) => void;
  hide: () => void;
};

const DEFAULT_DURATION = 2500;

const ToastContext = createContext<ToastContextValue | null>(null);

export function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext);
  if (!ctx) {
    throw new Error('useToast must be used inside <ToastProvider>');
  }
  return ctx;
}

type InternalToast = {
  id: number;
  message: string;
  variant: ToastVariant;
  duration: number;
};

export function ToastProvider({ children }: { children: React.ReactNode }) {
  const [toast, setToast] = useState<InternalToast | null>(null);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const clearTimer = () => {
    if (timerRef.current) {
      clearTimeout(timerRef.current);
      timerRef.current = null;
    }
  };

  const hide = useCallback(() => {
    clearTimer();
    setToast(null);
  }, []);

  const show = useCallback((t: ToastPayload) => {
    clearTimer();
    const id = Date.now();
    const duration = t.duration ?? DEFAULT_DURATION;
    setToast({
      id,
      message: t.message,
      variant: t.variant ?? 'info',
      duration,
    });
    timerRef.current = setTimeout(() => {
      timerRef.current = null;
      // Only clear if this toast still owns the slot (show() may have replaced it).
      setToast((cur) => (cur?.id === id ? null : cur));
    }, duration);
  }, []);

  useEffect(() => () => clearTimer(), []);

  const value = useMemo<ToastContextValue>(() => ({ show, hide }), [show, hide]);

  return (
    <ToastContext.Provider value={value}>
      {children}
      {toast ? <ToastSurface toast={toast} onDismiss={hide} /> : null}
    </ToastContext.Provider>
  );
}

type VariantPalette = { bg: string; border: string };

const VARIANT_PALETTE: Record<ToastVariant, VariantPalette> = {
  success: { bg: colors.successSoft, border: colors.success },
  error: { bg: colors.dangerSoft, border: colors.danger },
  info: { bg: colors.primarySoft, border: colors.primary },
};

type ToastSurfaceProps = {
  toast: InternalToast;
  onDismiss: () => void;
};

function ToastSurface({ toast, onDismiss }: ToastSurfaceProps) {
  const reduced = useReducedMotion();
  const translateY = useSharedValue(-140);
  const progress = useSharedValue(1);
  const trackWidth = useSharedValue(0);

  useEffect(() => {
    // Reset each time a new toast replaces the slot (toast.id changes) so the
    // enter spring + progress countdown replay from their start positions.
    translateY.value = -140;
    translateY.value = withSpring(
      0,
      withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
    );
    progress.value = 1;
    if (!reduced) {
      progress.value = withTiming(0, {
        duration: toast.duration,
        easing: Easing.linear,
      });
    }
    return () => {
      cancelAnimation(translateY);
      cancelAnimation(progress);
    };
  }, [toast.id, toast.duration, reduced, translateY, progress]);

  const handleTrackLayout = (event: LayoutChangeEvent) => {
    trackWidth.value = event.nativeEvent.layout.width;
  };

  const bannerStyle = useAnimatedStyle(() => ({
    transform: [{ translateY: translateY.value }],
  }));

  const progressFillStyle = useAnimatedStyle(() => ({
    width: trackWidth.value * progress.value,
  }));

  const palette = VARIANT_PALETTE[toast.variant];

  return (
    <SafeAreaView pointerEvents="box-none" style={styles.root}>
      <Animated.View
        pointerEvents="auto"
        style={[
          styles.banner,
          { backgroundColor: palette.bg, borderColor: palette.border },
          shadows.hard,
          bannerStyle,
        ]}
        accessibilityLiveRegion="polite"
        accessibilityRole="alert"
      >
        <View style={styles.row}>
          <Text
            style={[textStyles.body, styles.message, { color: colors.ink }]}
            numberOfLines={3}
          >
            {toast.message}
          </Text>
          <Pressable
            onPress={onDismiss}
            accessibilityRole="button"
            accessibilityLabel="Dismiss notification"
            hitSlop={8}
          >
            <X size={18} color={colors.ink} strokeWidth={2.5} />
          </Pressable>
        </View>
        <View
          style={[styles.progressTrack, { backgroundColor: colors.surface }]}
          onLayout={handleTrackLayout}
        >
          <Animated.View
            style={[styles.progressFill, { backgroundColor: palette.border }, progressFillStyle]}
          />
        </View>
      </Animated.View>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  root: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    alignItems: 'center',
    zIndex: 9999,
    elevation: 9999,
  },
  banner: {
    marginTop: spacing.sm,
    width: '92%',
    maxWidth: 520,
    borderRadius: radii.card,
    borderWidth: 2,
    paddingVertical: spacing.md,
    paddingHorizontal: spacing.base,
  },
  row: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: spacing.sm,
  },
  message: {
    flex: 1,
  },
  progressTrack: {
    marginTop: spacing.sm,
    height: 3,
    borderRadius: radii.pill,
    overflow: 'hidden',
  },
  progressFill: {
    height: '100%',
    borderRadius: radii.pill,
  },
});

import { useCallback, useEffect, useMemo } from 'react';
import {
  Modal,
  Pressable,
  type StyleProp,
  StyleSheet,
  useWindowDimensions,
  View,
  type ViewStyle,
} from 'react-native';
import {
  Gesture,
  GestureDetector,
  GestureHandlerRootView,
} from 'react-native-gesture-handler';
import Animated, {
  runOnJS,
  useAnimatedStyle,
  useSharedValue,
  withSpring,
  withTiming,
  type WithSpringConfig,
} from 'react-native-reanimated';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { SPRING_SNAPPY, withReducedMotion } from '@/design/motion';
import { useReducedMotion } from '@/design/useReducedMotion';

// Modal bottom sheet per docs/design.md §3.3 ("Bottom sheet (80% height)") +
// §6 inventory (children, snapPoints). Slides up on open with SPRING_SNAPPY per
// §1.4 line 99. Drag-to-dismiss via react-native-gesture-handler PanGesture:
// snap to the nearest provided snap point, or dismiss when pulled past the
// lowest snap + threshold or flung downward.
//
// snapPoints are fractions of screen height. The FIRST entry is the initial
// (and largest) snap — sheet height is set from it. Additional smaller entries
// create peek positions the user can drag to.
const DISMISS_VELOCITY = 600; // px/s — fling-dismiss threshold
const DISMISS_DRAG_OVERSHOOT = 0.25; // extra drag past lowest snap before dismissing (as fraction of sheetHeight)

export type BottomSheetProps = {
  visible: boolean;
  onDismiss: () => void;
  children: React.ReactNode;
  snapPoints?: readonly number[];
  style?: StyleProp<ViewStyle>;
  accessibilityLabel?: string;
  testID?: string;
};

export function BottomSheet({
  visible,
  onDismiss,
  children,
  snapPoints = [0.8],
  style,
  accessibilityLabel,
  testID,
}: BottomSheetProps) {
  const reduced = useReducedMotion();
  const { height: screenHeight } = useWindowDimensions();

  const { sheetHeight, snapOffsets } = useMemo(() => {
    const sorted = [...snapPoints]
      .map((p) => clamp(p, 0.2, 0.95))
      .sort((a, b) => b - a);
    const primary = sorted[0] ?? 0.8;
    const h = screenHeight * primary;
    // snapOffsets[0] is always 0 (fully shown at primary snap). Subsequent
    // entries are positive translateY offsets sliding the sheet down for peeks.
    const offsets = sorted.map((p) => h * (1 - p / primary));
    return { sheetHeight: h, snapOffsets: offsets };
  }, [snapPoints, screenHeight]);

  const translateY = useSharedValue(sheetHeight);
  const backdropOpacity = useSharedValue(0);
  const gestureStart = useSharedValue(0);

  useEffect(() => {
    if (visible) {
      translateY.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced));
      backdropOpacity.value = withTiming(1, { duration: reduced ? 0 : 180 });
    } else {
      translateY.value = withSpring(
        sheetHeight,
        withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
      );
      backdropOpacity.value = withTiming(0, { duration: reduced ? 0 : 160 });
    }
  }, [visible, reduced, sheetHeight, translateY, backdropOpacity]);

  const dismissFromJS = useCallback(() => {
    onDismiss();
  }, [onDismiss]);

  const pan = useMemo(
    () =>
      Gesture.Pan()
        .onStart(() => {
          gestureStart.value = translateY.value;
        })
        .onUpdate((e) => {
          translateY.value = Math.max(0, gestureStart.value + e.translationY);
        })
        .onEnd((e) => {
          const final = translateY.value;
          const largestOffset = snapOffsets[snapOffsets.length - 1] ?? 0;
          const shouldDismiss =
            final > largestOffset + sheetHeight * DISMISS_DRAG_OVERSHOOT ||
            e.velocityY > DISMISS_VELOCITY;
          if (shouldDismiss) {
            runOnJS(dismissFromJS)();
            return;
          }
          let nearest = snapOffsets[0] ?? 0;
          let bestDist = Math.abs(final - nearest);
          for (const o of snapOffsets) {
            const d = Math.abs(final - o);
            if (d < bestDist) {
              bestDist = d;
              nearest = o;
            }
          }
          translateY.value = withSpring(
            nearest,
            withReducedMotion<WithSpringConfig>(SPRING_SNAPPY, reduced),
          );
        }),
    [gestureStart, translateY, snapOffsets, sheetHeight, reduced, dismissFromJS],
  );

  const sheetAnimatedStyle = useAnimatedStyle(() => ({
    transform: [{ translateY: translateY.value }],
  }));

  const backdropAnimatedStyle = useAnimatedStyle(() => ({
    opacity: backdropOpacity.value * 0.45,
  }));

  return (
    <Modal
      visible={visible}
      transparent
      onRequestClose={onDismiss}
      animationType="none"
      statusBarTranslucent
      testID={testID}
    >
      {/* New GestureHandlerRootView inside Modal — on Android, Modal opens a new
          window that does not inherit the root handler from app/_layout.tsx. */}
      <GestureHandlerRootView style={styles.root}>
        <Animated.View style={[styles.backdrop, backdropAnimatedStyle]}>
          <Pressable
            style={StyleSheet.absoluteFill}
            onPress={onDismiss}
            accessibilityRole="button"
            accessibilityLabel="Dismiss sheet"
          />
        </Animated.View>
        <GestureDetector gesture={pan}>
          <Animated.View
            style={[styles.sheet, { height: sheetHeight }, shadows.hard, sheetAnimatedStyle, style]}
            accessibilityViewIsModal
            accessibilityLabel={accessibilityLabel}
          >
            <View style={styles.handle} />
            <View style={styles.content}>{children}</View>
          </Animated.View>
        </GestureDetector>
      </GestureHandlerRootView>
    </Modal>
  );
}

function clamp(v: number, min: number, max: number) {
  return Math.min(max, Math.max(min, v));
}

const styles = StyleSheet.create({
  root: {
    flex: 1,
    justifyContent: 'flex-end',
  },
  backdrop: {
    ...StyleSheet.absoluteFillObject,
    backgroundColor: colors.ink,
  },
  sheet: {
    backgroundColor: colors.canvas,
    borderTopLeftRadius: radii.card,
    borderTopRightRadius: radii.card,
    borderWidth: 2,
    borderBottomWidth: 0,
    borderColor: colors.ink,
    paddingTop: spacing.sm,
    // Shadow on a bottom-pinned sheet reads upward.
    shadowOffset: { width: 0, height: -3 },
  },
  handle: {
    alignSelf: 'center',
    width: 48,
    height: 4,
    borderRadius: radii.pill,
    backgroundColor: colors.ink40,
    marginBottom: spacing.sm,
  },
  content: {
    flex: 1,
    paddingHorizontal: spacing.xl,
    paddingBottom: spacing.xxl + spacing.base, // covers iOS home-indicator area
  },
});

